```typescript
export type RestaurantState =
  | { status: "none" }
  | { status: "open"; id: string; openedAt: string; covers: number }
  | { status: "closed"; id: string; closedAt: string };

export type RestaurantCommand =
  | { type: "openRestaurant"; id: string; at: string }
  | { type: "seatGuests"; count: number }
  | { type: "closeRestaurant"; at: string };

export type RestaurantEvent =
  | { type: "RestaurantOpened"; id: string; at: string }
  | { type: "GuestsSeated"; count: number }
  | { type: "RestaurantClosed"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const restaurantDecider: Decider<RestaurantCommand, RestaurantEvent, RestaurantState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "openRestaurant": {
        if (state.status === "open") throw new DomainError("ALREADY_OPEN");
        return [{ type: "RestaurantOpened", id: command.id, at: command.at }];
      }
      case "seatGuests": {
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (command.count <= 0) throw new DomainError("INVALID_COUNT");
        return [{ type: "GuestsSeated", count: command.count }];
      }
      case "closeRestaurant": {
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "RestaurantClosed", at: command.at }];
      }
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "RestaurantOpened":
        return { status: "open", id: event.id, openedAt: event.at, covers: 0 };
      case "GuestsSeated":
        return state.status === "open"
          ? { ...state, covers: state.covers + event.count }
          : state;
      case "RestaurantClosed":
        return state.status === "open"
          ? { status: "closed", id: state.id, closedAt: event.at }
          : state;
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
