```typescript
export type ReceiptEvent =
  | { type: "ReceiptIssued"; receiptId: string; day: string; cents: number; tip: number }
  | { type: "ReceiptVoided"; receiptId: string; day: string; cents: number; tip: number }
  | { type: "ReceiptPrinted"; receiptId: string }
  | { type: "ReceiptEmailed"; receiptId: string };

export type DailyTotal = Readonly<{ day: string; gross: number; tips: number; count: number }>;

export type ReceiptView = Readonly<{
  byDay: Readonly<Record<string, DailyTotal>>;
}>;

export const emptyView: ReceiptView = { byDay: {} };

function bump(view: ReceiptView, day: string, cents: number, tip: number, countDelta: number): ReceiptView {
  const existing: DailyTotal = view.byDay[day] ?? { day, gross: 0, tips: 0, count: 0 };
  const next: DailyTotal = {
    day,
    gross: existing.gross + cents,
    tips: existing.tips + tip,
    count: existing.count + countDelta,
  };
  return { byDay: { ...view.byDay, [day]: next } };
}

export function project(view: ReceiptView, event: ReceiptEvent): ReceiptView {
  switch (event.type) {
    case "ReceiptIssued":
      return bump(view, event.day, event.cents, event.tip, 1);
    case "ReceiptVoided":
      return bump(view, event.day, -event.cents, -event.tip, -1);
    case "ReceiptPrinted":
    case "ReceiptEmailed":
      // Not relevant to the financial totals view.
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
