export type WaiterSessionEvent =
  | { type: "SessionOpened"; waiterId: string; sessionId: string }
  | { type: "TipRecorded"; waiterId: string; cents: number }
  | { type: "SessionClosed"; waiterId: string; sessionId: string }
  | { type: "BreakTaken"; waiterId: string };

export type WaiterStats = Readonly<{
  waiterId: string;
  sessions: number;
  tipsCents: number;
}>;

export type WaiterView = Readonly<{
  byWaiter: Readonly<Record<string, WaiterStats>>;
}>;

export const emptyView: WaiterView = { byWaiter: {} };

function get(view: WaiterView, waiterId: string): WaiterStats {
  return view.byWaiter[waiterId] ?? { waiterId, sessions: 0, tipsCents: 0 };
}

export function project(view: WaiterView, event: WaiterSessionEvent): WaiterView {
  switch (event.type) {
    case "SessionOpened": {
      const s = get(view, event.waiterId);
      return { byWaiter: { ...view.byWaiter, [event.waiterId]: { ...s, sessions: s.sessions + 1 } } };
    }
    case "TipRecorded": {
      const s = get(view, event.waiterId);
      return { byWaiter: { ...view.byWaiter, [event.waiterId]: { ...s, tipsCents: s.tipsCents + event.cents } } };
    }
    case "SessionClosed":
    case "BreakTaken":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function projectWaiterView(events: WaiterSessionEvent[]): WaiterView {
  return events.reduce(project, emptyView);
}
