```typescript
export type BarTabEvent =
  | { type: "TabOpened"; tabId: string; guest: string }
  | { type: "DrinkPoured"; tabId: string; cents: number }
  | { type: "FoodAdded"; tabId: string; cents: number }
  | { type: "TabClosed"; tabId: string };

export type TabInfo = Readonly<{
  tabId: string;
  guest: string;
  totalCents: number;
  lineCount: number;
  closed: boolean;
}>;

export type BarTabView = Readonly<{
  tabs: Readonly<Record<string, TabInfo>>;
}>;

export const emptyView: BarTabView = { tabs: {} };

function addLine(view: BarTabView, tabId: string, cents: number): BarTabView {
  const existing = view.tabs[tabId];
  if (!existing) return view;
  const next: TabInfo = {
    ...existing,
    totalCents: existing.totalCents + cents,
    lineCount: existing.lineCount + 1,
  };
  return { tabs: { ...view.tabs, [tabId]: next } };
}

export function project(view: BarTabView, event: BarTabEvent): BarTabView {
  switch (event.type) {
    case "TabOpened": {
      const info: TabInfo = { tabId: event.tabId, guest: event.guest, totalCents: 0, lineCount: 0, closed: false };
      return { tabs: { ...view.tabs, [event.tabId]: info } };
    }
    case "DrinkPoured":
    case "FoodAdded":
      return addLine(view, event.tabId, event.cents);
    case "TabClosed": {
      const existing = view.tabs[event.tabId];
      if (!existing) return view;
      return { tabs: { ...view.tabs, [event.tabId]: { ...existing, closed: true } } };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}
