export type RestaurantV1 = { id: string; openedAt: string };
export type RestaurantV2 = { id: string; openedAt: string; covers: number };
export type RestaurantV3 = { id: string; shiftStartedAt: string; covers: number };

export type CurrentRestaurant = RestaurantV3;

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 3;

function v1Tov2(snap: Snapshot<RestaurantV1>): Snapshot<RestaurantV2> {
