  if (current.version === 2) current = v2Tov3(current as Snapshot<RestaurantV2>);
  if (current.version !== CURRENT_VERSION) {
    throw new SnapshotError(`UNSUPPORTED_VERSION_${current.version}`);
  }
  return current as Snapshot<CurrentRestaurant>;
