export interface StoredEvent<E> { readonly revision: bigint; readonly event: E }

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(
    stream: string,
    events: E[],
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: bigint | string) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export type KitchenOrderEvent =
  | { type: "TicketQueued"; ticket: number }
  | { type: "CookingStarted"; at: string };

export async function appendKitchenOrder(
  store: EventStore<KitchenOrderEvent>,
  stream: string,
  events: KitchenOrderEvent[],
  expected: bigint | "no_stream"
): Promise<bigint> {
  try {
    const { nextRevision } = await store.appendToStream(stream, events, { expectedRevision: expected });
    return nextRevision;
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    if (msg.toLowerCase().includes("revision") || msg.toLowerCase().includes("conflict")) {
      throw new ConcurrencyConflict(stream, expected);
    }
    throw err;
  }
}
