  | { type: "TicketQueued"; id: string }
  | { type: "CookingStarted" }
  | { type: "OrderReady" };

const initial: KitchenOrderState = { status: "none" };

function evolve(s: KitchenOrderState, e: KitchenOrderEvent): KitchenOrderState {
  switch (e.type) {
    case "TicketQueued": return { status: "queued", id: e.id };
    case "CookingStarted":
      return s.status === "queued" ? { status: "cooking", id: s.id } : s;
    case "OrderReady":
      return s.status === "cooking" ? { status: "ready", id: s.id } : s;
    default: { const _n: never = e; return s; }
  }
}

export class DomainError extends Error { constructor(m: string) { super(m); this.name = "DomainError"; } }

function decide(c: KitchenOrderCommand, s: KitchenOrderState): KitchenOrderEvent[] {
  switch (c.type) {
    case "queue":
      if (s.status !== "none") throw new DomainError("QUEUED");
      return [{ type: "TicketQueued", id: c.id }];
    case "startCooking":
      if (s.status !== "queued") throw new DomainError("NOT_QUEUED");
      return [{ type: "CookingStarted" }];
    case "markReady":
      if (s.status !== "cooking") throw new DomainError("NOT_COOKING");
      return [{ type: "OrderReady" }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(s: string): AsyncIterable<{ revision: bigint; event: KitchenOrderEvent }>;
  appendToStream(s: string, ev: KitchenOrderEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export async function handleKitchenOrder(
  cmd: KitchenOrderCommand,
  ctx: { streamName: string; eventStore: EventStore }
): Promise<void> {
  let state = initial;
  let rev: bigint | "no_stream" = "no_stream";
  for await (const { revision, event } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    rev = revision;
  }
  const events = decide(cmd, state);
  if (events.length > 0) {
    await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: rev });
  }
