export type RestaurantEvent =
  | { type: "RestaurantOpened"; id: string }
  | { type: "GuestsSeated"; count: number }
  | { type: "RestaurantClosed" };

export type OccupancyView = Readonly<{ seated: number; isOpen: boolean }>;
const empty: OccupancyView = { seated: 0, isOpen: false };

export function project(view: OccupancyView, e: RestaurantEvent): OccupancyView {
  switch (e.type) {
    case "RestaurantOpened": return { seated: 0, isOpen: true };
    case "GuestsSeated": return { ...view, seated: view.seated + e.count };
    case "RestaurantClosed": return { ...view, isOpen: false };
    default: { const _n: never = e; return view; }
  }
