  save(view: OccupancyView): Promise<void>;
}

export async function runSubscription(
  ctx: { feed: EventFeed; checkpoints: CheckpointStore; views: ViewStore },
  stream: string,
  subscriptionName: string
): Promise<void> {
  const from = await ctx.checkpoints.read(subscriptionName);
  let view: OccupancyView = empty;
  for await (const { revision, event } of ctx.feed.readFrom(stream, from)) {
    view = project(view, event);
    // Save the view BEFORE the checkpoint so a crash replays, never skips.
    await ctx.views.save(view);
    await ctx.checkpoints.write(subscriptionName, revision);
  }
