export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S
): Promise<S> {
  let state: S = initial;
  for await (const event of events) {
    state = evolve(state, event);
  }
  return state;
}

// Example usage with a Receipt aggregate.
export type ReceiptEvent =
  | { type: "ReceiptIssued"; cents: number }
  | { type: "ReceiptVoided" };

export type ReceiptState = Readonly<{ totalCents: number; voided: boolean }>;

function evolve(s: ReceiptState, e: ReceiptEvent): ReceiptState {
  switch (e.type) {
    case "ReceiptIssued": return { ...s, totalCents: s.totalCents + e.cents };
    case "ReceiptVoided": return { ...s, voided: true };
    default: { const _n: never = e; return s; }
  }
}

export async function rebuildReceipt(events: AsyncIterable<ReceiptEvent>): Promise<ReceiptState> {
  return aggregateStream<ReceiptState, ReceiptEvent>(events, evolve, { totalCents: 0, voided: false });
}
