export type ReceiptEvent =
  | { type: "ReceiptIssued"; receiptId: string; cents: number }
  | { type: "ReceiptVoided"; receiptId: string };

export interface OutboxRow {
  readonly id: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export interface TxConn {
  insertOutbox(rows: OutboxRow[]): Promise<void>;
  appendToStream(stream: string, events: ReceiptEvent[], expected: bigint | "no_stream"): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface TxProvider {
  begin(): Promise<TxConn>;
}

// Publisher (not shown): a worker polls outbox where publishedAt IS NULL,
// sends the payload to the bus, then updates publishedAt.
export async function appendWithOutbox(
  provider: TxProvider,
  stream: string,
  events: ReceiptEvent[],
  outboxRows: OutboxRow[],
  expected: bigint | "no_stream"
): Promise<void> {
  const tx = await provider.begin();
  try {
    await tx.appendToStream(stream, events, expected);
    await tx.insertOutbox(outboxRows);
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}
