  | { type: "issueReceipt"; id: string; cents: number }
  | { type: "voidReceipt" };

export type ReceiptEvent =
  | { type: "ReceiptIssued"; id: string; cents: number }
  | { type: "ReceiptVoided" };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export function decide(command: ReceiptCommand, state: ReceiptState): ReceiptEvent[] {
  switch (command.type) {
    case "issueReceipt":
      if (state.status !== "none") throw new DomainError("ALREADY_ISSUED");
      if (command.cents <= 0) throw new DomainError("NON_POSITIVE_AMOUNT");
      return [{ type: "ReceiptIssued", id: command.id, cents: command.cents }];
    case "voidReceipt":
      if (state.status !== "issued") throw new DomainError("NOT_ISSUED");
      return [{ type: "ReceiptVoided" }];
    default: {
      const _n: never = command;
      throw new DomainError("UNKNOWN");
    }
  }
}
